def reset():
    global _value
    _value = 0


def get():
    return _value


def _set(v):
    global _value
    _value = v


def run_steps(steps):
    results = []
    for fn, args in steps:
        results.append(fn(*args))
    return results


def make_increment_steps():
    """Return a single atomic increment step.

    The previous version split increment into separate read and write steps,
    which allowed two concurrent increments to both read the same value and
    overwrite each other. By making increment atomic within one step, the
